/**
 * Model User
 * ──────────────────────────────────────────────────────────
 * USER
 * ──────────────────────────────────────────────────────────
 * Central identity for authentication and all ownership references.
 * 
 * WHY IT EXISTS:
 * Every action in the system (creating a group, paying an expense,
 * recording a settlement, importing a CSV) must be attributable to
 * an authenticated user. This table stores JWT-compatible credentials
 * and serves as the FK target for all "who did this?" columns.
 * ──────────────────────────────────────────────────────────
 */
export type User = $Result.DefaultSelection<Prisma.$UserPayload>
/**
 * Model Group
 * ──────────────────────────────────────────────────────────
 * GROUP
 * ──────────────────────────────────────────────────────────
 * A named container that scopes expenses, memberships, and
 * settlements together.
 * 
 * WHY IT EXISTS:
 * Splitwise-style apps organize financial activity into groups
 * (e.g. "Goa Trip", "Flatmates"). Every expense, settlement,
 * and membership interval is scoped to exactly one group.
 * The creator is tracked for ownership and admin privileges.
 * ──────────────────────────────────────────────────────────
 */
export type Group = $Result.DefaultSelection<Prisma.$GroupPayload>
/**
 * Model GroupMembership
 * ──────────────────────────────────────────────────────────
 * GROUP MEMBERSHIP
 * ──────────────────────────────────────────────────────────
 * A temporal interval recording when a user was an active
 * member of a group.  joinedAt marks the start; leftAt marks
 * the end (NULL = currently active).
 * 
 * WHY IT EXISTS:
 * Members can join and leave groups over time. A user who
 * leaves and re-joins gets a NEW row, creating a complete
 * audit history. When recording an expense, the system queries
 * this table to determine who was active on the expense date:
 * 
 * WHERE joinedAt <= expenseDate
 * AND (leftAt IS NULL OR leftAt > expenseDate)
 * 
 * This ensures expenses only affect members who were present.
 * ──────────────────────────────────────────────────────────
 */
export type GroupMembership = $Result.DefaultSelection<Prisma.$GroupMembershipPayload>
/**
 * Model Expense
 * ──────────────────────────────────────────────────────────
 * EXPENSE
 * ──────────────────────────────────────────────────────────
 * A single expense event: "User X paid ₹1200 for dinner on
 * 2024-03-15 in Group Y, split equally."
 * 
 * WHY IT EXISTS:
 * This is the core financial record. It captures WHO paid,
 * HOW MUCH, in WHAT CURRENCY, WHEN it happened, and HOW
 * it should be divided. The actual per-person obligations
 * are stored in ExpenseShare (child rows).
 * 
 * Settlements are intentionally stored in a separate table
 * to avoid polluting expense queries and balance aggregations.
 * ──────────────────────────────────────────────────────────
 */
export type Expense = $Result.DefaultSelection<Prisma.$ExpensePayload>
/**
 * Model ExpenseShare
 * ──────────────────────────────────────────────────────────
 * EXPENSE SHARE
 * ──────────────────────────────────────────────────────────
 * The individual obligation a participant owes for a single
 * expense. One row per participant per expense.
 * 
 * WHY IT EXISTS:
 * An expense of ₹1200 split among 4 people produces 4 share
 * rows of ₹300 each. Storing pre-computed absolute amounts
 * (even for percentage splits) avoids rounding drift on reads
 * and makes balance queries a simple SUM().
 * 
 * Balance formula uses this table:
 * owes(A→B) = SUM(shares where A is userId AND expense.paidBy = B)
 * – SUM(shares where B is userId AND expense.paidBy = A)
 * ──────────────────────────────────────────────────────────
 */
export type ExpenseShare = $Result.DefaultSelection<Prisma.$ExpenseSharePayload>
/**
 * Model Settlement
 * ──────────────────────────────────────────────────────────
 * SETTLEMENT
 * ──────────────────────────────────────────────────────────
 * A direct payment from one member to another to reduce debt.
 * e.g. "Alice paid Bob ₹500 to settle up."
 * 
 * WHY IT EXISTS:
 * Settlements are NOT expenses — they don't generate shares or
 * affect who owes what for a specific purchase. They only reduce
 * the net balance between two people. Keeping them separate
 * ensures:
 * 1. Expense queries aren't polluted with settlement records
 * 2. Balance formula is clean:
 * net(A→B) = expense_debt(A→B) – settlements(A→B) + settlements(B→A)
 * 3. Settlement history is independently auditable
 * ──────────────────────────────────────────────────────────
 */
export type Settlement = $Result.DefaultSelection<Prisma.$SettlementPayload>
/**
 * Model Import
 * ──────────────────────────────────────────────────────────
 * IMPORT
 * ──────────────────────────────────────────────────────────
 * Tracks a single CSV import operation as a batch. Records who
 * triggered it, which group it targets, and aggregate results.
 * 
 * WHY IT EXISTS:
 * CSV imports can create dozens of expenses at once. This table
 * provides:
 * 1. Batch identity: group all imported expenses under one run
 * 2. Progress tracking: totalRows vs successCount vs failureCount
 * 3. Audit trail: who imported what, when
 * 4. Parent for ImportAnomaly rows (every issue is traceable
 * back to a specific import run)
 * ──────────────────────────────────────────────────────────
 */
export type Import = $Result.DefaultSelection<Prisma.$ImportPayload>
/**
 * Model ImportAnomaly
 * ──────────────────────────────────────────────────────────
 * IMPORT ANOMALY
 * ──────────────────────────────────────────────────────────
 * A single issue detected on a single CSV row during import.
 * One row in this table = one anomaly.
 * 
 * WHY IT EXISTS:
 * The requirement states "every anomaly detected during import
 * must be logged and traceable." This table satisfies that by
 * recording:
 * - WHICH import batch (importId → Import)
 * - WHICH row in the CSV (rowNumber)
 * - WHAT went wrong (type enum + human-readable message)
 * - HOW severe (WARNING = partially imported, ERROR = skipped)
 * - THE RAW DATA (rawData JSONB preserves the original CSV
 * row for post-mortem debugging without re-uploading)
 * ──────────────────────────────────────────────────────────
 */
export type ImportAnomaly = $Result.DefaultSelection<Prisma.$ImportAnomalyPayload>
/**
 * Model ImportRow
 * ──────────────────────────────────────────────────────────
 * IMPORT ROW
 * ──────────────────────────────────────────────────────────
 * Records the verdict and data for every row processed during
 * a CSV import.
 * 
 * WHY IT EXISTS:
 * Required for full auditability of the import process. This
 * ensures no row is ever silently dropped. It links to the
 * created expense (if imported) or records the user review
 * decision (if flagged).
 * ──────────────────────────────────────────────────────────
 */
export type ImportRow = $Result.DefaultSelection<Prisma.$ImportRowPayload>

